import React, { useState, useEffect, useCallback } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import './Home.css';

const CATEGORIES = [
  'All', 'Medical', 'Education', 'Social',
  'Environment', 'Animal Welfare', 'Disaster Relief', 'Other'
];

const CATEGORY_EMOJI = {
  Medical: '🏥', Education: '📚', Social: '🤝',
  Environment: '🌿', 'Animal Welfare': '🐾',
  'Disaster Relief': '⛑️', Other: '💡'
};

const TRUST_BADGES = [
  { icon: '🔒', text: '100% Secure Payments' },
  { icon: '✅', text: 'Verified Campaigns' },
  { icon: '🏦', text: 'Razorpay Protected' },
  { icon: '💳', text: 'Zero Hidden Fees' },
];

// ── Campaign Card ──────────────────────────────────────────────
const CampaignCard = ({ campaign }) => {
  const progress = Math.min(Math.round((campaign.raised / campaign.goal) * 100), 100);
  const daysAgo = Math.floor((Date.now() - new Date(campaign.createdAt)) / 86400000);
  const isUrgent = campaign.raised < campaign.goal * 0.1 && daysAgo > 5;

  return (
    <Link
      to={`/campaigns/${campaign._id}`}
      className="campaign-card"
      id={`campaign-card-${campaign._id}`}
      aria-label={`View campaign: ${campaign.title}`}
    >
      <div className="campaign-image-wrapper">
        {campaign.imageUrl ? (
          <img
            src={campaign.imageUrl}
            alt={campaign.title}
            className="campaign-image"
            loading="lazy"
            onError={(e) => {
              e.target.onerror = null;
              e.target.src = `https://picsum.photos/seed/${campaign._id}/600/340`;
            }}
          />
        ) : (
          <div className="campaign-image-placeholder">
            {CATEGORY_EMOJI[campaign.category] || '💡'}
          </div>
        )}
        <span className="campaign-category-tag">{campaign.category}</span>
        {isUrgent && <span className="campaign-urgent-tag">🔴 Urgent</span>}
      </div>

      <div className="campaign-body">
        <h3 className="campaign-title">{campaign.title}</h3>
        <p className="campaign-desc">{campaign.description}</p>

        <div className="campaign-progress-area">
          <div className="progress-bar-wrapper">
            <div
              className="progress-bar-fill"
              style={{ width: `${progress}%` }}
              role="progressbar"
              aria-valuenow={progress}
              aria-valuemin="0"
              aria-valuemax="100"
            />
          </div>
          <div className="campaign-progress-labels">
            <span className="raised-label">
              ₹{campaign.raised.toLocaleString('en-IN')} raised
            </span>
            <span className="percent-label">{progress}%</span>
          </div>
        </div>

        <div className="campaign-footer">
          <div className="campaign-creator">
            <div className="creator-dot">
              {(campaign.creator?.name || 'A').charAt(0).toUpperCase()}
            </div>
            {campaign.creator?.name || 'Anonymous'}
          </div>
          <span className="campaign-goal-tag">
            Goal: ₹{campaign.goal.toLocaleString('en-IN')}
          </span>
        </div>
      </div>
    </Link>
  );
};

// ── Home Page ──────────────────────────────────────────────────
const Home = () => {
  const [campaigns, setCampaigns] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [search, setSearch] = useState('');
  const [activeCategory, setActiveCategory] = useState('All');
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [total, setTotal] = useState(0);

  const fetchCampaigns = useCallback(async () => {
    try {
      setLoading(true);
      setError('');
      const params = { page, limit: 9 };
      if (activeCategory !== 'All') params.category = activeCategory;
      if (search.trim()) params.search = search.trim();
      const { data } = await axios.get('/api/campaigns', { params });
      setCampaigns(data.campaigns);
      setTotalPages(data.totalPages);
      setTotal(data.total);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to load campaigns. Please try again.');
    } finally {
      setLoading(false);
    }
  }, [page, activeCategory, search]);

  useEffect(() => {
    const t = setTimeout(fetchCampaigns, 300);
    return () => clearTimeout(t);
  }, [fetchCampaigns]);

  const handleCategory = (cat) => { setActiveCategory(cat); setPage(1); };

  return (
    <div className="home-page">
      {/* ── Hero ────────────────────────────────────────────── */}
      <section className="hero-section" id="hero" aria-label="Hero section">
        <div className="hero-shapes">
          <div className="hero-blob hero-blob-1" />
          <div className="hero-blob hero-blob-2" />
          <div className="hero-blob hero-blob-3" />
          <div className="hero-grid-pattern" />
        </div>

        <div className="container hero-content">
          <div className="hero-eyebrow">
            <span>💙</span>
            India's Most Trusted Crowdfunding Platform
          </div>

          <h1 className="hero-title">
            Give Hope. Change Lives.<br />
            <span className="highlight">Fund</span>{' '}
            <span className="highlight-green">Every Dream</span>.
          </h1>

          <p className="hero-sub">
            Join over 1 million compassionate donors supporting medical emergencies,
            education, disaster relief, and social causes across India.
          </p>

          <div className="hero-actions">
            <Link to="/create-campaign" className="btn-hero-primary" id="hero-start-btn">
              🚀 Start a Campaign
            </Link>
            <a href="#campaigns-section" className="btn-hero-outline" id="hero-explore-btn">
              💙 Explore Causes
            </a>
          </div>

          <div className="hero-trust-bar">
            {[
              { num: '10K+', label: 'Campaigns' },
              { num: '₹50Cr+', label: 'Raised' },
              { num: '1M+', label: 'Donors' },
              { num: '98%', label: 'Success Rate' },
            ].map((s, i, arr) => (
              <React.Fragment key={s.label}>
                <div className="trust-stat">
                  <span className="trust-stat-number">{s.num}</span>
                  <span className="trust-stat-label">{s.label}</span>
                </div>
                {i < arr.length - 1 && <div className="trust-divider" />}
              </React.Fragment>
            ))}
          </div>
        </div>
      </section>

      {/* ── Trust Strip ─────────────────────────────────────── */}
      <div className="trust-strip" id="trust-strip">
        <div className="container">
          <div className="trust-strip-inner">
            {TRUST_BADGES.map((b) => (
              <div key={b.text} className="trust-badge">
                <span className="trust-badge-icon">{b.icon}</span>
                {b.text}
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* ── Campaigns Section ────────────────────────────────── */}
      <section className="campaigns-section" id="campaigns-section" aria-label="Campaigns">
        <div className="container">
          <div className="section-header">
            <h2>Active Campaigns</h2>
            <p>Every rupee counts. Find a cause that speaks to your heart.</p>
          </div>

          {/* Filters */}
          <div className="filters-wrapper" id="filters-wrapper">
            <div className="search-box">
              <span className="search-icon">🔍</span>
              <input
                type="text"
                id="campaign-search"
                className="search-input-styled"
                placeholder="Search campaigns by title, description..."
                value={search}
                onChange={(e) => { setSearch(e.target.value); setPage(1); }}
                aria-label="Search campaigns"
              />
            </div>
            <div className="category-pills" id="category-pills" role="tablist">
              {CATEGORIES.map((cat) => (
                <button
                  key={cat}
                  id={`cat-${cat.replace(/\s+/g, '-').toLowerCase()}`}
                  className={`category-pill ${activeCategory === cat ? 'category-pill-active' : ''}`}
                  onClick={() => handleCategory(cat)}
                  role="tab"
                  aria-selected={activeCategory === cat}
                >
                  {cat !== 'All' && CATEGORY_EMOJI[cat] + ' '}{cat}
                </button>
              ))}
            </div>
          </div>

          {/* Results bar */}
          {!loading && (
            <div className="results-bar" id="results-bar">
              <span className="results-count">
                {total === 0 ? 'No campaigns found' : `${total} campaign${total !== 1 ? 's' : ''}`}
                {activeCategory !== 'All' && ` in ${activeCategory}`}
              </span>
            </div>
          )}

          {/* Content */}
          {loading ? (
            <div className="loading-state" id="campaigns-loading">
              <div className="spinner spinner-lg" />
              <p>Loading campaigns...</p>
            </div>
          ) : error ? (
            <div className="alert alert-error" id="campaigns-error" role="alert">
              <span>⚠️</span>
              <p>{error} <button className="btn btn-sm btn-secondary" style={{marginLeft:'0.5rem'}} onClick={fetchCampaigns}>Retry</button></p>
            </div>
          ) : campaigns.length === 0 ? (
            <div className="empty-state" id="empty-campaigns">
              <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>🔍</div>
              <h3>No campaigns found</h3>
              <p>Try a different search or category, or be the first to create one!</p>
              <Link to="/create-campaign" className="btn btn-primary" id="empty-create-btn">
                Start a Campaign
              </Link>
            </div>
          ) : (
            <div className="campaigns-grid" id="campaigns-grid">
              {campaigns.map((c) => <CampaignCard key={c._id} campaign={c} />)}
            </div>
          )}

          {/* Pagination */}
          {!loading && totalPages > 1 && (
            <div className="pagination" id="pagination">
              <button
                className="btn btn-secondary btn-sm"
                onClick={() => setPage((p) => Math.max(1, p - 1))}
                disabled={page === 1}
                id="btn-prev"
              >
                ← Previous
              </button>
              <span className="pagination-info">Page {page} of {totalPages}</span>
              <button
                className="btn btn-secondary btn-sm"
                onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
                disabled={page === totalPages}
                id="btn-next"
              >
                Next →
              </button>
            </div>
          )}
        </div>
      </section>

      {/* ── CTA Strip ───────────────────────────────────────── */}
      <section className="donate-cta-strip" id="cta-strip" aria-label="Call to action">
        <div className="container">
          <h2>Every Rupee Makes a Difference 💙</h2>
          <p>
            Whether it's ₹10 or ₹10,000 — your generosity creates ripples of change
            in someone's life today.
          </p>
          <div className="donate-cta-buttons">
            <Link to="/create-campaign" className="btn-hero-primary" id="cta-start-btn">
              🚀 Start a Campaign
            </Link>
            <a href="#campaigns-section" className="btn-hero-outline" id="cta-donate-btn">
              💙 Donate Now
            </a>
          </div>
        </div>
      </section>
    </div>
  );
};

export default Home;
